import java.util.Stack;

public int longestValidParentheses(String s) {
    int n = s.length();
    int result = 0;
    Stack<Integer> st = new Stack<>();

    for (int i = 0; i < n; ++i) {
        if (s.charAt(i) == '(') {
            st.push(i);
        } else {
            if (!st.empty() && s.charAt(st.peek()) == '(') {
                st.pop();
            } else {
                st.push(i);
            }
        }
    }

    if (st.empty()) {
        result = n;
    } else {
        int right = n, left = 0;
        while (!st.empty()) {
            left = st.pop();
            result = Math.max(result, right - left - 1);
            right = left;
        }
        result = Math.max(result, right);
    }

    return result;
}
```

